const cons={s:o=>{console.log("%c[SUCCESS]%c "+o,"color:white;background:green;","")},w:o=>{console.log("%c[WARNING]%c "+o,"color:brown;background:yellow;","")},i:o=>{console.log("%c[INFO]%c "+o,"color:white;background:blue;","")},e:o=>{console.log("%c[ERROR]%c "+o,"color:white;background:red;","")},d:o=>{console.log("%c[DEBUG]%c "+o,"color:white;background:black;","")}};export default cons;